mapper.select:
SELECT *
FROM (
	SELECT ROWNUM AS RNUM, T1.*
	FROM (
		SELECT
		O.ORDER_TOTAL_PRICE,O.ORDER_DATE,O.ORDER_ID, P.PRODUCT_NAME,P.PRODUCT_PHOTO1,S.DELIVERY_STATUS 
		FROM ORDERS O
		JOIN ORDER_DETAIL OD ON O.ORDER_ID = OD.ORDER_ID
		JOIN PRODUCT P ON OD.PRODUCT_ID = P.PRODUCT_ID
		JOIN DELIVERY D  ON O.ORDER_ID = D.ORDER_ID
        JOIN STATUS S ON D.DELIVERY_ID = S.DELIVERY_ID	  
		WHERE MEMBER_NO =#{memberNo}

			AND ORDER_DATE >= SYSDATE - #{period}


			AND ORDER_DATE BETWEEN #{startDate} AND #{endDate}

		ORDER BY ORDER_DATE
		) T1
)
WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT COUNT(*)
FROM ORDERS O
JOIN ORDER_DETAIL OD ON O.ORDER_ID = OD.ORDER_ID
JOIN PRODUCT P ON OD.PRODUCT_ID = P.PRODUCT_ID 
JOIN DELIVERY D ON O.ORDER_ID = D.ORDER_ID
JOIN STATUS S ON D.DELIVERY_ID = S.DELIVERY_ID	
WHERE MEMBER_NO = #{memberNo}


	AND ORDER_DATE >= SYSDATE - #{period}



	AND ORDER_DATE BETWEEN #{startDate} AND #{endDate}

SELECT *
FROM (
	SELECT ROWNUM AS RNUM, T1.*
FROM (
SELECT R.PRODUCT_ID, R.VIEWED_DATE, P.PRODUCT_NAME, P.PRODUCT_PHOTO1, P.PRODUCT_PRICE
FROM RECENTLY_VIEWED R
JOIN PRODUCT P ON P.PRODUCT_ID = R.PRODUCT_ID
WHERE MEMBER_NO = #{memberNo}


	AND VIEWED_DATE >= SYSDATE - #{period}



	AND VIEWED_DATE BETWEEN #{startDate} AND #{endDate}

ORDER BY VIEWED_DATE

) T1
)
WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT COUNT(*)
FROM RECENTLY_VIEWED
WHERE MEMBER_NO = #{memberNo}


	AND VIEWED_DATE >= SYSDATE - #{period}



	AND VIEWED_DATE BETWEEN #{startDate} AND #{endDate}

SELECT *
FROM (
SELECT
ROWNUM AS RNUM, T1.*
FROM (
SELECT *
FROM INQUIRY
WHERE MEMBER_NO =
#{memberNo}
ORDER BY INQUIRY_REG_DATE

) T1
)
WHERE RNUM BETWEEN #{offset}
AND #{limit}
